// Логотип A-Count (фирменный, встроен как PNG с прозрачностью).
// variant="dark"  — тёмный текст, для светлых поверхностей (регистрация, печать)
// variant="light" — белый текст, для тёмно-зелёного сайдбара
const DARK = 'data:image/png;base64,'
const LIGHT = 'data:image/png;base64,'

export default function Logo({ height = 34, variant = 'light' }: { height?: number; variant?: 'dark' | 'light' }) {
  return <img src={variant === 'dark' ? DARK : LIGHT} alt="A-Count — Simple Accounting Platform"
              style={{ height, width: 'auto', display: 'block' }} />
}
